#include<bits/stdc++.h>
using namespace std;
long long dp[100010][1010],s[1010],n,k;
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&k);
    if(n>=k)
    {
        for(long long i=0;i<k;i++)
        {
            printf("%lld ",fastpow(k,mod-2));
        }
        return 0;
    }
    dp[1][0]=1;
    for(long long i=2;i<=n;i++)
    {
        memset(s,0,sizeof(s));
        long long x=i-1;
        for(long long j=0;j<k;j++)
        {
            long long val=dp[i-1][j]*fastpow(i,mod-2)%mod;
            if(j+x<k)
            {
                s[j]=(s[j]+val)%mod;
                s[j+x+1]=((s[j+x+1]-val)%mod+mod)%mod;
            }
            else
            {
                s[j]=(s[j]+val)%mod;
                s[k]=((s[k]-val)%mod+mod)%mod;
                s[0]=(s[0]+val)%mod;
                s[j+x-k+1]=((s[j+x-k+1]-val)%mod+mod)%mod;
            }
        }
        for(long long j=1;j<k;j++)
        {
            s[j]=(s[j]+s[j-1])%mod;
        }
        for(long long j=0;j<k;j++)
        {
            dp[i][j]=s[j];
        }
    }
    for(long long i=0;i<k;i++)
    {
        printf("%lld ",dp[n][i]);
    }
    return 0;
}
